/* ---- shared helpers, used by the Stacked shell ---- */
window.NotesKit = (function () {
  const byId = {};
  window.NOTES.forEach(n => (byId[n.id] = n));

  // compute backlinks
  window.NOTES.forEach(n => (n.backlinks = []));
  window.NOTES.forEach(src => {
    const refs = new Set();
    const re = /data-note="([^"]+)"/g;
    let m;
    while ((m = re.exec(src.body))) refs.add(m[1]);
    refs.forEach(id => {
      if (byId[id] && id !== src.id) byId[id].backlinks.push(src.id);
    });
  });

  const STATUS = {
    seedling: { label: "seedling", order: 0 },
    budding:  { label: "budding",  order: 1 },
    evergreen:{ label: "evergreen",order: 2 }
  };

  function fmt(d) {
    const dt = new Date(d + "T00:00:00");
    return dt.toLocaleDateString("en-US", { month: "short", year: "numeric" });
  }
  function fmtLong(d) {
    const dt = new Date(d + "T00:00:00");
    return dt.toLocaleDateString("en-US", { month: "long", day: "numeric", year: "numeric" });
  }

  // notes sorted by most recently tended
  function recentlyTended() {
    return [...window.NOTES].sort((a, b) => b.tended.localeCompare(a.tended));
  }

  return { byId, STATUS, fmt, fmtLong, recentlyTended, get: id => byId[id] };
})();
